  "instructions": {
    "text_instructions": [
      {
        "id": "01f13ac6049f1df2983a6180290a82ea",
        "content": [
          "You are a Population Health Analytics expert specializing in pharmaceutical market intelligence for Eli Lilly. Your role is to help researchers, data scientists, and business analysts uncover insights about patient populations, disease patterns, healthcare utilization, and real-world evidence.\n",
          "\n",
          "**Your Approach:**\n",
          "- Provide clear, actionable insights with business context relevant to pharmaceutical research\n",
          "- Highlight geographic patterns, temporal trends, and demographic variations\n",
          "- When showing diagnosis codes, include their clinical meaning when possible (e.g., I10 = Essential Hypertension)\n",
          "- Surface unexpected patterns or anomalies that warrant further investigation\n",
          "- Use percentage changes and year-over-year comparisons for trend analysis\n",
          "- Default to recent time periods (last 12-24 months) unless specified otherwise\n",
          "\n",
          "**Data Context:**\n",
          "- This dataset covers 7 years (2017-2023) of healthcare claims across 42 US states\n",
          "- Patient population skews older (largest group: 65+) with Medicare/commercial payer mix\n",
          "- Key therapeutic areas represented: cardiovascular, endocrine/metabolic, preventive care\n",
          "- Claims include professional services, hospital visits, procedures, and diagnoses\n",
          "\n",
          "**Response Style:**\n",
          "- Lead with the key finding, then supporting details\n",
          "- Use comparative language (\"X is 2.3x higher than Y\")\n",
          "- Flag data quality considerations when relevant\n",
          "- Suggest logical follow-up analyses when appropriate"
        ]
      }
    ],
    "example_question_sqls": [
      {
        "id": "01f13ac6aea611b89ea08f11d8f0269f",
        "question": [
          "Join patients with their diagnoses"
        ],
        "sql": [
          "SELECT \n",
          "  p.patient_id,\n",
          "  p.age,\n",
          "  p.gender,\n",
          "  p.state,\n",
          "  d.diagnosis_code,\n",
          "  COUNT(*) as diagnosis_count\n",
          "FROM eli_lilly_demo.gold_claims.patient_summary p\n",
          "INNER JOIN eli_lilly_demo.silver_claims.diagnosis d \n",
          "  ON p.patient_id = d.patient_id\n",
          "WHERE d.diagnosis_code IS NOT NULL\n",
          "GROUP BY p.patient_id, p.age, p.gender, p.state, d.diagnosis_code"
        ],
        "usage_guidance": [
          "Use this pattern when users ask about patient characteristics combined with their diagnoses, such as 'show me ages of patients with diabetes' or 'which states have the most cardiovascular patients'."
        ]
      },
      {
        "id": "01f13ac6be8a1f71ac9dc9d216670000",
        "question": [
          "Complete patient journey across all tables"
        ],
        "sql": [
          "SELECT \n",
          "  p.patient_id,\n",
          "  p.age,\n",
          "  p.gender,\n",
          "  p.state,\n",
          "  p.total_claims,\n",
          "  e.benefit_type,\n",
          "  e.enrollment_days,\n",
          "  COUNT(DISTINCT d.diagnosis_code) as unique_diagnoses,\n",
          "  COUNT(DISTINCT ca.location_of_care) as unique_care_locations\n",
          "FROM eli_lilly_demo.gold_claims.patient_summary p\n",
          "LEFT JOIN eli_lilly_demo.silver_claims.enrollment e \n",
          "  ON p.patient_id = e.patient_id\n",
          "LEFT JOIN eli_lilly_demo.silver_claims.diagnosis d \n",
          "  ON p.patient_id = d.patient_id\n",
          "LEFT JOIN eli_lilly_demo.gold_claims.claims_analytics ca \n",
          "  ON p.patient_id = ca.patient_id\n",
          "GROUP BY p.patient_id, p.age, p.gender, p.state, p.total_claims, e.benefit_type, e.enrollment_days"
        ],
        "usage_guidance": [
          "Use this for comprehensive patient-level analysis that requires data from multiple tables, such as 'give me a full profile of high-utilizing patients' or 'show me patient complexity by combining diagnoses, locations, and enrollment'"
        ]
      }
    ]
  },
  "benchmarks": {
    "questions": [
      {
        "id": "01f13ac637f41417bbfc0ddf883ff3e3",
        "question": [
          "How many unique patients have cardiovascular diagnoses (I10, I25, I50)?"
        ],
        "answer": [
          {
            "format": "SQL",
            "content": [
              "SELECT \n",
              "  COUNT(DISTINCT d.patient_id) AS patient_count\n",
              "FROM eli_lilly_demo.silver_claims.diagnosis d\n",
              "WHERE d.diagnosis_code IN ('I10', 'I25', 'I50')"
            ]
          }
        ]
      },
      {
        "id": "01f13ac63013138a86be7c075bf642ff",
        "question": [
          "Which states have more than 100 patients"
        ],
        "answer": [
          {
            "format": "SQL",
            "content": [
              "SELECT \n",
              "  state,\n",
              "  COUNT(DISTINCT patient_id) AS patient_count\n",
              "FROM eli_lilly_demo.gold_claims.patient_summary\n",
              "WHERE state IS NOT NULL\n",
              "GROUP BY state\n",
              "HAVING COUNT(DISTINCT patient_id) > 100\n",
              "ORDER BY patient_count DESC"
            ]
          }
        ]
      },
      {
        "id": "01f13ac62afb1d359524e65139660c9f",
        "question": [
          "Show me total claims by month for 2023"
        ],
        "answer": [
          {
            "format": "SQL",
            "content": [
              "SELECT \n",
              "  service_month,\n",
              "  SUM(total_claims) AS monthly_claims\n",
              "FROM eli_lilly_demo.gold_claims.claims_analytics\n",
              "WHERE service_year = 2023\n",
              "GROUP BY service_month\n",
              "ORDER BY service_month"
            ]
          }
        ]
      },
      {
        "id": "01f13ac6263f1105bcd05f5714cc10f0",
        "question": [
          "What are the top 5 diagnosis codes by frequency?"
        ],
        "answer": [
          {
            "format": "SQL",
            "content": [
              "SELECT \n",
              "  diagnosis_code,\n",
              "  COUNT(*) AS diagnosis_count\n",
              "FROM eli_lilly_demo.silver_claims.diagnosis\n",
              "WHERE diagnosis_code IS NOT NULL\n",
              "GROUP BY diagnosis_code\n",
              "ORDER BY diagnosis_count DESC\n",
              "LIMIT 5"
            ]
          }
        ]
      },
      {
        "id": "01f13ac614b313f68967d25e9b9e8ee5",
        "question": [
          "How many patients do we have by gender?"
        ],
        "answer": [
          {
            "format": "SQL",
            "content": [
              "SELECT \n",
              "  gender,\n",
              "  COUNT(DISTINCT patient_id) AS patient_count\n",
              "FROM eli_lilly_demo.gold_claims.patient_summary\n",
              "WHERE gender IS NOT NULL\n",
              "GROUP BY gender\n",
              "ORDER BY patient_count DESC"
            ]
          }
        ]
      }
    ]
  }
